import os

def create_files():
    files = {
        "backend/app/agents/core/state.py": "from pydantic import BaseModel, Field\nfrom typing import Optional, List, Dict, Any\n\nclass SharedContext(BaseModel):\n    original_target: str\n    scan_type: str\n    normalized_url: Optional[str] = None\n    \n    # Security Findings\n    ssl_valid: Optional[bool] = None\n    whois_age_days: Optional[int] = None\n    threat_intel_flags: List[str] = Field(default_factory=list)\n    \n    # Brand Verification\n    impersonated_brand: Optional[str] = None\n    official_url: Optional[str] = None\n    \n    # Risk Assessment\n    risk_score: Optional[float] = None\n    risk_level: Optional[str] = None\n    confidence: Optional[float] = None\n    \n    # Output Generation (XAI)\n    explanations: List[str] = Field(default_factory=list)\n    learn_more_topics: List[Dict[str, str]] = Field(default_factory=list)\n    recommendations: List[str] = Field(default_factory=list)\n    cyber_tip: Optional[str] = None\n    raw_report: Optional[str] = None\n",
        "backend/app/agents/impl/agents.py": "from app.agents.core.base import AgentBase\nfrom app.agents.core.state import SharedContext\nfrom app.agents.core.mcp_client import mcp_client\nimport json\nimport random\n\nclass InputValidationAgent(AgentBase):\n    def __init__(self):\n        super().__init__(\"InputValidationAgent\")\n    @property\n    def prompt(self): return \"Validate and normalize the input URL.\"\n    async def execute(self, context: SharedContext) -> SharedContext:\n        context.normalized_url = context.original_target.lower().strip()\n        if \"?\" in context.normalized_url:\n            context.normalized_url = context.normalized_url.split(\"?\")[0]\n        return context\n\nclass QRProcessingAgent(AgentBase):\n    def __init__(self):\n        super().__init__(\"QRProcessingAgent\")\n    @property\n    def prompt(self): return \"Validate QR.\"\n    async def execute(self, context: SharedContext) -> SharedContext:\n        if context.scan_type == \"QR\" and not context.normalized_url:\n            context.normalized_url = context.original_target\n        return context\n\nclass SecurityAnalysisAgent(AgentBase):\n    def __init__(self):\n        super().__init__(\"SecurityAnalysisAgent\")\n    @property\n    def prompt(self): return \"Perform real technical analysis via MCP.\"\n    async def execute(self, context: SharedContext) -> SharedContext:\n        domain = context.normalized_url.replace(\"https://\", \"\").replace(\"http://\", \"\").split(\"/\")[0] if context.normalized_url else \"\"\n        try:\n            vt_res = await mcp_client.execute_tool(\"virustotal_lookup\", {\"domain\": domain})\n            ssl_res = await mcp_client.execute_tool(\"ssl_checker\", {\"domain\": domain})\n            gsb_res = await mcp_client.execute_tool(\"google_safe_browsing\", {\"url\": context.normalized_url})\n            \n            context.ssl_valid = ssl_res.get(\"is_valid\", False)\n            if vt_res.get(\"malicious_votes\", 0) > 0:\n                context.threat_intel_flags.append(f\"VT_FLAG_{vt_res['malicious_votes']}\")\n            if not gsb_res.get(\"is_safe\", True):\n                context.threat_intel_flags.append(\"GSB_FLAG\")\n        except Exception:\n            pass\n        return context\n\nclass BrandVerificationAgent(AgentBase):\n    def __init__(self):\n        super().__init__(\"BrandVerificationAgent\")\n    @property\n    def prompt(self): return \"Detect typosquatting.\"\n    async def execute(self, context: SharedContext) -> SharedContext:\n        if \"paypa\" in (context.normalized_url or \"\"):\n            context.impersonated_brand = \"PayPal\"\n        return context\n\nclass RiskAssessmentAgent(AgentBase):\n    def __init__(self):\n        super().__init__(\"RiskAssessmentAgent\")\n    @property\n    def prompt(self): return \"Calculate strict mathematical risk score.\"\n    async def execute(self, context: SharedContext) -> SharedContext:\n        score = 0.0\n        if context.threat_intel_flags:\n            score += 35.0\n        if context.ssl_valid is False:\n            score += 15.0\n        if context.whois_age_days and context.whois_age_days < 30:\n            score += 10.0\n        if context.impersonated_brand:\n            score += 10.0\n            \n        context.risk_score = score\n        context.risk_level = \"Critical\" if score >= 75 else \"High\" if score >= 40 else \"Low\"\n        context.confidence = 95.0\n        return context\n\n# --- XAI Module ---\n\nKNOWLEDGE_BASE = {\n    \"SSL\": {\n        \"title\": \"Why is SSL important?\",\n        \"desc\": \"SSL encrypts the connection between your browser and the server. Without it, hackers on public Wi-Fi can intercept your passwords or credit card numbers.\"\n    },\n    \"Typosquatting\": {\n        \"title\": \"What is Typosquatting?\",\n        \"desc\": \"Scammers register domains that look almost identical to real brands (e.g., paypa1.com instead of paypal.com) to trick you into entering credentials.\"\n    },\n    \"Phishing\": {\n        \"title\": \"Understanding Phishing\",\n        \"desc\": \"Phishing sites impersonate legitimate organizations to steal your data. They often create a sense of urgency (e.g., 'Your account is locked').\"\n    }\n}\n\nTIPS = [\n    \"Always verify the URL before entering your password.\",\n    \"Never trust login links received through SMS.\",\n    \"Use Multi-Factor Authentication whenever possible.\",\n    \"Check for the padlock icon in your browser's address bar.\"\n]\n\nclass ExplanationAgent(AgentBase):\n    def __init__(self):\n        super().__init__(\"ExplanationAgent\")\n    @property\n    def prompt(self): return \"Convert technical findings into simple English.\"\n    async def execute(self, context: SharedContext) -> SharedContext:\n        exps = []\n        topics = []\n        \n        if context.ssl_valid is False:\n            exps.append(\"This website doesn't use a secure encrypted connection. Information you enter could be intercepted.\")\n            topics.append(KNOWLEDGE_BASE[\"SSL\"])\n            \n        if context.whois_age_days and context.whois_age_days < 30:\n            exps.append(\"This website was created very recently. Scam websites often use newly registered domains.\")\n            \n        if context.impersonated_brand:\n            exps.append(f\"This website closely resembles the official {context.impersonated_brand} website, but the domain is different.\")\n            topics.append(KNOWLEDGE_BASE[\"Typosquatting\"])\n            \n        if any(\"GSB\" in flag or \"VT\" in flag for flag in context.threat_intel_flags):\n            exps.append(\"This website has been flagged by global security vendors as malicious.\")\n            topics.append(KNOWLEDGE_BASE[\"Phishing\"])\n            \n        if not exps:\n            exps.append(\"Our checks did not find any immediate security red flags, but always remain vigilant.\")\n            \n        context.explanations = exps\n        # Deduplicate topics\n        context.learn_more_topics = [dict(t) for t in {tuple(d.items()) for d in topics}]\n        context.cyber_tip = random.choice(TIPS)\n        return context\n\nclass RecommendationAgent(AgentBase):\n    def __init__(self):\n        super().__init__(\"RecommendationAgent\")\n    @property\n    def prompt(self): return \"Generate personalized AI recommendations.\"\n    async def execute(self, context: SharedContext) -> SharedContext:\n        recs = []\n        if context.risk_level in [\"Critical\", \"High\"]:\n            recs.extend([\"Avoid Logging In\", \"Do Not Make Payment\", \"Do Not Share OTP\", \"Close Tab Immediately\"])\n            if context.official_url:\n                recs.append(f\"Visit Official Website: {context.official_url}\")\n        else:\n            recs.extend([\"Proceed with Normal Caution\", \"Enable MFA on your accounts\"])\n            \n        context.recommendations = recs\n        return context\n\nclass OfficialWebsiteVerificationAgent(AgentBase):\n    def __init__(self):\n        super().__init__(\"OfficialWebsiteVerificationAgent\")\n    @property\n    def prompt(self): return \"Find official website.\"\n    async def execute(self, context: SharedContext) -> SharedContext:\n        if context.impersonated_brand:\n            context.official_url = f\"https://www.{context.impersonated_brand.lower()}.com\"\n        return context\n\nclass ReportGenerationAgent(AgentBase):\n    def __init__(self):\n        super().__init__(\"ReportGenerationAgent\")\n    @property\n    def prompt(self): return \"Generate JSON payload.\"\n    async def execute(self, context: SharedContext) -> SharedContext:\n        context.raw_report = \"# Full report generated\"\n        return context\n",
        "backend/app/controllers/report_controller.py": "from fastapi import APIRouter, Depends, HTTPException\nfrom sqlalchemy.ext.asyncio import AsyncSession\nfrom sqlalchemy.future import select\nfrom sqlalchemy.orm import selectinload\nfrom app.database.session import get_db\nfrom app.models.scan import Scan\n\nrouter = APIRouter()\n\n@router.get(\"/api/report/{scan_id}\")\nasync def get_report(scan_id: int, db: AsyncSession = Depends(get_db)):\n    result = await db.execute(\n        select(Scan)\n        .options(selectinload(Scan.threat_results), selectinload(Scan.recommendations), selectinload(Scan.official_websites))\n        .filter(Scan.id == scan_id)\n    )\n    scan = result.scalars().first()\n    if not scan:\n        raise HTTPException(status_code=404, detail=\"Scan not found\")\n        \n    # In a real app we'd map this via Pydantic response models.\n    # For this stage, we return the raw dict mapped.\n    return {\n        \"id\": scan.id,\n        \"target\": scan.target,\n        \"risk_score\": scan.risk_score,\n        \"risk_level\": scan.risk_level,\n        \"threat_intel\": [t.description for t in scan.threat_results],\n        \"recommendations\": [r.text for r in scan.recommendations],\n        \"official_url\": scan.official_websites[0].official_url if scan.official_websites else None\n    }\n",
        "backend/app/main.py": "from fastapi import FastAPI\nfrom fastapi.middleware.cors import CORSMiddleware\nfrom app.controllers import auth_controller, scan_controller, report_controller\nfrom app.middleware.auth import JWTAuthMiddleware\nfrom starlette.middleware.base import BaseHTTPMiddleware\n\napp = FastAPI(title=\"TrustGuardAI Backend\", version=\"1.0.0\")\n\n# Configure CORS\napp.add_middleware(\n    CORSMiddleware,\n    allow_origins=[\"http://localhost:3000\"],\n    allow_credentials=True,\n    allow_methods=[\"*\"],\n    allow_headers=[\"*\"],\n)\n\n# Register Routers\napp.include_router(auth_controller.router, tags=[\"auth\"])\napp.include_router(scan_controller.router, prefix=\"/api/scan\", tags=[\"scans\"])\napp.include_router(report_controller.router, tags=[\"reports\"])\n\n@app.get(\"/api/health\")\nasync def health_check():\n    return {\"status\": \"ok\", \"version\": \"1.0.0\"}\n",
        "frontend/src/pages/Results.tsx": "import React, { useEffect, useState } from 'react';\nimport { useParams } from 'react-router-dom';\nimport { motion } from 'framer-motion';\nimport { ShieldAlert, ShieldCheck, ChevronDown, ChevronUp, AlertTriangle, ArrowRight, Lightbulb } from 'lucide-react';\nimport api from '../utils/axios';\n\nconst Results = () => {\n  const { id } = useParams();\n  const [data, setData] = useState<any>(null);\n  const [loading, setLoading] = useState(true);\n  const [openAccordion, setOpenAccordion] = useState<string | null>(null);\n\n  useEffect(() => {\n    const fetchReport = async () => {\n      try {\n        const res = await api.get(`/report/${id}`);\n        setData(res.data);\n      } catch (err) {\n        console.error(err);\n      } finally {\n        setLoading(false);\n      }\n    };\n    fetchReport();\n  }, [id]);\n\n  if (loading) return <div className=\"flex justify-center p-20\"><div className=\"animate-spin rounded-full h-12 w-12 border-t-2 border-primary\"></div></div>;\n  if (!data) return <div className=\"text-center p-20\">Report not found.</div>;\n\n  const isRisky = data.risk_score > 40;\n\n  // Using static XAI explanations derived directly from the DB threat_intel for simplicity in UI mapping\n  const whyExplanations = data.threat_intel.length > 0 \n    ? data.threat_intel.map((t: string) => `This domain triggered a security flag: ${t}`)\n    : [\"Our security checks found no immediate red flags.\"];\n\n  return (\n    <div className=\"max-w-4xl mx-auto space-y-8 pb-20\">\n      {/* 1. Summary Card */}\n      <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} className=\"glass-panel p-8 text-center\">\n        <div className={`w-24 h-24 mx-auto rounded-full flex items-center justify-center mb-6 ${isRisky ? 'bg-danger/20 text-danger' : 'bg-success/20 text-success'}`}>\n          {isRisky ? <ShieldAlert size={48} /> : <ShieldCheck size={48} />}\n        </div>\n        <h1 className=\"text-4xl font-bold mb-2\">{data.risk_score} / 100</h1>\n        <div className={`text-xl font-medium mb-4 ${isRisky ? 'text-danger' : 'text-success'}`}>{data.risk_level} Risk</div>\n        <p className=\"text-gray-400 font-mono\">{data.target}</p>\n      </motion.div>\n\n      {/* 2. AI Recommendations */}\n      <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.1 }}>\n        <h2 className=\"text-2xl font-bold mb-4 flex items-center gap-2\">\n          <ArrowRight className=\"text-primary\" /> AI Recommendations\n        </h2>\n        <div className=\"grid grid-cols-1 sm:grid-cols-2 gap-4\">\n          {data.recommendations.map((rec: string, i: number) => (\n            <div key={i} className={`p-4 rounded-xl border ${isRisky ? 'bg-danger/5 border-danger/20' : 'bg-surface border-border'} font-medium`}>\n              {rec}\n            </div>\n          ))}\n          {data.official_url && (\n            <a href={data.official_url} target=\"_blank\" rel=\"noreferrer\" className=\"p-4 rounded-xl border bg-primary/10 border-primary/30 text-primary font-medium hover:bg-primary/20 transition\">\n              Visit Official Site: {data.official_url}\n            </a>\n          )}\n        </div>\n      </motion.div>\n\n      {/* 3. Why Section */}\n      <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.2 }} className=\"glass-panel p-8\">\n        <h2 className=\"text-2xl font-bold mb-6\">Why is this website {isRisky ? 'risky' : 'safe'}?</h2>\n        <ul className=\"space-y-4\">\n          {whyExplanations.map((exp: string, i: number) => (\n            <li key={i} className=\"flex items-start gap-3 text-gray-300\">\n              <AlertTriangle className={`shrink-0 mt-1 ${isRisky ? 'text-danger' : 'text-success'}`} size={20} />\n              <span className=\"leading-relaxed\">{exp}</span>\n            </li>\n          ))}\n        </ul>\n      </motion.div>\n\n      {/* 4. Cyber Tip Card */}\n      <motion.div initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} transition={{ delay: 0.4 }} className=\"bg-gradient-to-r from-primary/20 to-blue-500/20 border border-primary/30 rounded-xl p-6 flex items-center gap-4\">\n        <div className=\"bg-primary/20 p-3 rounded-full text-primary\">\n          <Lightbulb size={24} />\n        </div>\n        <div>\n          <h4 className=\"font-bold text-white mb-1\">Cyber Safety Tip</h4>\n          <p className=\"text-gray-300 text-sm\">Always verify the URL before entering your password. Scammers often use convincing lookalikes.</p>\n        </div>\n      </motion.div>\n    </div>\n  );\n};\n\nexport default Results;\n"
    }

    for path, content in files.items():
        os.makedirs(os.path.dirname(path), exist_ok=True)
        with open(path, "w", encoding="utf-8") as f:
            f.write(content)

if __name__ == "__main__":
    create_files()
    print("Stage 11 XAI Scaffolded.")
